const fs=require("fs"),path=require("path"),mongoose=require("mongoose");require("dotenv").config();const BASE_URL="https://www.universcolis.fr";mongoose.connect(process.env.MONGO_URL);const Article=require("../../models/Article"),Actualite=require("../../models/Actualite"),Question=require("../../models/Question");async function getStaticPages(){return[{loc:"/",priority:1},{loc:"/suivi",priority:1},{loc:"/conseils",priority:1},{loc:"/actualites",priority:.8},{loc:"/questions",priority:.9},{loc:"/mon-materiel",priority:.6},{loc:"/comment-ca-marche",priority:.4},{loc:"/qui-sommes-nous",priority:.4},{loc:"/politique-confidentialite",priority:.4},{loc:"/mentions-legales",priority:.4},{loc:"/contact",priority:.4},{loc:"/suivi/statuts-colis",priority:.8}]}async function getArticles(){return(await Article.find({}).select("slug publishedDate modifiedDate ogImage ogDescription title seoTitle ").lean()).map(e=>{let t;if(e.modifiedDate){const i=new Date(e.modifiedDate);isNaN(i)||(t=i.toISOString().split("T")[0])}else if(e.publishedDate){const i=new Date(e.publishedDate);isNaN(i)||(t=i.toISOString().split("T")[0])}return{loc:`/conseils/${e.slug}`,priority:.9,lastmod:t,ogImage:e.ogImage||null,ogDescription:e.ogDescription||"",title:e.title||e.seoTitle||e.slug.replace(/-/g," ")}})}async function getActualites(){return(await Actualite.find({}).select("slug publishedDate modifiedDate ogImage actualiteImgName actualiteImgDescription title seoTitle").lean()).map(e=>{let t;if(e.modifiedDate){const i=new Date(e.modifiedDate);isNaN(i)||(t=i.toISOString().split("T")[0])}else if(e.publishedDate){const i=new Date(e.publishedDate);isNaN(i)||(t=i.toISOString().split("T")[0])}return{loc:`/actualites/${e.slug}`,priority:.8,lastmod:t,ogImage:e.ogImage||null,actualiteImgName:e.actualiteImgName||"",actualiteImgDescription:e.actualiteImgDescription||"",title:e.title||e.seoTitle||e.slug.replace(/-/g," ")}})}async function getQuestions(){return(await Question.find({}).select("slug category publishedDate modifiedDate questionImg questionImgName questionImgDescription").lean()).map(e=>{let t;if(e.modifiedDate){const i=new Date(e.modifiedDate);isNaN(i)||(t=i.toISOString().split("T")[0])}else if(e.publishedDate){const i=new Date(e.publishedDate);isNaN(i)||(t=i.toISOString().split("T")[0])}return{loc:`/questions/${e.category}/${e.slug}`,priority:.9,lastmod:t,questionImg:e.questionImg?`${BASE_URL}/static/img/questionsImg/${e.questionImg}`:null,questionImgName:e.questionImgName||"",questionImgDescription:e.questionImgDescription||""}})}async function getImages(e,t){const i=[];return i.push({page:"/",images:[{url:`${BASE_URL}/static/img/logo.png`,name:"UniversColis Logo",description:"Logo UniversColis"}]}),i.push({page:"/mon-materiel",images:[{url:`${BASE_URL}/static/img/materiel.jpg`,name:"Matériel d'emballage",description:"Matériel d'emballage pour colis"}]}),t.forEach(e=>{e.loc.startsWith("/conseils/")&&e.ogImage&&i.push({page:e.loc,images:[{url:e.ogImage,description:e.ogDescription||""}]}),e.loc.startsWith("/actualites/")&&e.ogImage&&i.push({page:e.loc,images:[{url:e.ogImage,name:e.actualiteImgName||"",description:e.actualiteImgDescription||""}]})}),global.questionsList&&Array.isArray(global.questionsList)&&global.questionsList.forEach(e=>{e.questionImg&&i.push({page:e.loc,images:[{url:e.questionImg,name:e.questionImgName||"",description:e.questionImgDescription||""}]})}),i}function generateSitemapIndex(){return`<?xml version="1.0" encoding="UTF-8"?>\n<sitemapindex xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">\n  <sitemap>\n    <loc>${BASE_URL}/sitemap-pages.xml</loc>\n  </sitemap>\n  <sitemap>\n    <loc>${BASE_URL}/sitemap-articles.xml</loc>\n  </sitemap>\n  <sitemap>\n    <loc>${BASE_URL}/sitemap-questions.xml</loc>\n  </sitemap>\n  <sitemap>\n    <loc>${BASE_URL}/sitemap-images.xml</loc>\n  </sitemap>\n</sitemapindex>`}function generatePagesSitemap(e){return`<?xml version="1.0" encoding="UTF-8"?>\n<urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">\n${e.map(e=>`\n  <url>\n    <loc>${BASE_URL}${e.loc}</loc>\n    <priority>${e.priority}</priority>\n  </url>`).join("")}\n</urlset>`}function generateArticlesSitemap(e){return`<?xml version="1.0" encoding="UTF-8"?>\n<urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">\n${e.map(e=>`\n  <url>\n    <loc>${BASE_URL}${e.loc}</loc>\n    <priority>${e.priority}</priority>\n    ${e.lastmod?`<lastmod>${e.lastmod}</lastmod>`:""}\n    ${e.image?`<image:image xmlns:image="http://www.google.com/schemas/sitemap-image/1.1"><image:loc>${e.image}</image:loc></image:image>`:""}\n  </url>`).join("")}\n</urlset>`}function generateQuestionsSitemap(e){return`<?xml version="1.0" encoding="UTF-8"?>\n<urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">\n  ${e.map(e=>`\n    <url>\n      <loc>${BASE_URL}${e.loc}</loc>\n      <priority>0.7</priority>\n      ${e.lastmod?`<lastmod>${e.lastmod}</lastmod>`:""}\n    </url>`).join("")}\n  </urlset>`}function generateImagesSitemap(e){return`<?xml version="1.0" encoding="UTF-8"?>\n<urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9"\n        xmlns:image="http://www.google.com/schemas/sitemap-image/1.1">\n${e.map(e=>`<url>\n    <loc>${BASE_URL}${e.page}</loc>\n    ${e.images.map(e=>`\n      <image:image>\n        <image:loc>${e.url}</image:loc>\n        ${e.name?`<image:title>${e.name}</image:title>`:""}\n        ${e.description?`<image:caption>${e.description}</image:caption>`:""}\n      </image:image>\n    `).join("")}\n  </url>`).join("")}\n</urlset>`}function generateAtomFeed(e){return`<?xml version="1.0" encoding="utf-8"?>\n<feed xmlns="http://www.w3.org/2005/Atom">\n  <title>UniversColis - Nouveaux conseils et guides</title>\n  <link href="${BASE_URL}/atom.xml" rel="self"/>\n  <link href="https://pubsubhubbub.appspot.com/" rel="hub"/>\n  <updated>${(new Date).toISOString()}</updated>\n  <id>${BASE_URL}/</id>\n  ${e.map(e=>`\n    <entry>\n      <title>${e.title||e.loc.replace(/^\/[^/]+\//,"").replace(/-/g," ")}</title>\n      <link href="${BASE_URL}${e.loc}"/>\n      <id>${BASE_URL}${e.loc}</id>\n      ${e.lastmod?`<updated>${e.lastmod}</updated>`:""}\n      <summary>${e.summary||(e.loc.startsWith("/conseils/")?"Un nouveau guide est disponible.":"Une nouvelle actualité est disponible.")}\n      </summary>\n    </entry>\n  `).join("")}\n</feed>`}async function main(){const e=path.join(__dirname,"..");fs.existsSync(e)||fs.mkdirSync(e);const t=await getStaticPages(),i=await getArticles(),s=await getActualites(),n=await getQuestions(),o=s.length,a=Math.ceil(o/10),l=[];for(let e=2;e<=a;e++)l.push({loc:`/actualites?page=${e}`,priority:.8});const m=[...i,...s];global.questionsList=n;const r=await getImages(t,m),c=[...m,...l];fs.writeFileSync(path.join(e,"sitemap.xml"),generateSitemapIndex()),fs.writeFileSync(path.join(e,"sitemap-pages.xml"),generatePagesSitemap(t)),fs.writeFileSync(path.join(e,"sitemap-articles.xml"),generateArticlesSitemap(c)),fs.writeFileSync(path.join(e,"sitemap-questions.xml"),generateQuestionsSitemap(n)),fs.writeFileSync(path.join(e,"sitemap-images.xml"),generateImagesSitemap(r)),fs.writeFileSync(path.join(e,"atom.xml"),generateAtomFeed(m)),console.log("Sitemaps et Atom feed générés dans /static"),mongoose.disconnect()}main().catch(e=>{console.error(e),mongoose.disconnect(),process.exit(1)});